INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", 0, "vo_travel_talk", 0, "", 21, "", 1201820003, "", 20182, "vo_travel_talk_20018_00");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (0, 10, 118011, 1, 0, 11, 1, 1201820004, 0, 20182, "ぜぇ……ぜぇ……！\n本来、このような探索などは文官である\nわたくしの管轄外なのですけれど……！");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", "", 0, "", "", 91, "", 1201820005, "", 20182, "");
