INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", 0, "vo_travel_talk", 0, "", 21, "", 1201820007, "", 20182, "vo_travel_talk_20018_01");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (0, 10, 118011, 1, 0, 11, 1, 1201820008, 0, 20182, "陛下直々のご命令とあれば、\nこのクレジッタ・キャッシュ！\nご満足いただける大秘宝を、\nなんとしても手に入れてみせますわ！");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", "", 0, "", "", 91, "", 1201820009, "", 20182, "");
