INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", 0, "vo_travel_talk", 0, "", 21, "", 1201820011, "", 20182, "vo_travel_talk_20018_02");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (0, 10, 118011, 1, 0, 11, 1, 1201820012, 0, 20182, "……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", "", 0, "", "", 91, "", 1201820013, "", 20182, "");
